import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void negativeEdgeOnPath_correctSum() {
        // 0→1 (+1), 1→2 (-3), 2→3 (+2); total = 0
        int[][] edges = {{0,1,1},{1,2,-3},{2,3,2}};
        assertEquals(0, new Solution().bellmanFord(4, edges, 0, 3));
    }

    @Test
    void negativeCycleOnPathToDst_returnsIntMinValue() {
        // Cycle 1→2→1 has weight -5+2=-3 (negative); reachable from 0 and 2 is the dst
        int[][] edges = {{0,1,1},{1,2,-5},{2,1,2}};
        assertEquals(Integer.MIN_VALUE, new Solution().bellmanFord(3, edges, 0, 2));
    }

    @Test
    void unreachable_returnsMinusOne() {
        // Only edge goes 0→1; node 2 is unreachable
        int[][] edges = {{0,1,2}};
        assertEquals(-1, new Solution().bellmanFord(3, edges, 0, 2));
    }

    @Test
    void srcEqualsDst_returnsZero() {
        int[][] edges = {{0,1,5},{1,2,3}};
        assertEquals(0, new Solution().bellmanFord(3, edges, 1, 1));
    }

    @Test
    void negativeCycleNotOnPathToDst_stillReturnsNormalCost() {
        // Cycle between 2 and 3 (2→3→2 with net -1), but dst=1 is NOT reachable via cycle
        // Path 0→1 costs 4; cycle nodes 2,3 cannot reach 1
        int[][] edges = {{0,1,4},{0,2,1},{2,3,1},{3,2,-3}};
        assertEquals(4, new Solution().bellmanFord(4, edges, 0, 1));
    }

    @Test
    void allPositiveWeights_normalResult() {
        int[][] edges = {{0,1,2},{1,2,3},{0,2,10}};
        assertEquals(5, new Solution().bellmanFord(3, edges, 0, 2));
    }

    @Test
    void singleNode_noEdges_srcEqualsDst() {
        int[][] edges = {};
        assertEquals(0, new Solution().bellmanFord(1, edges, 0, 0));
    }
}
